mapper.select:
SELECT 'TABLE' AS OBJ_TYPE, table_name AS OBJ_NAME FROM information_schema.tables WHERE table_schema = #{schema} AND table_type = 'BASE TABLE'
UNION ALL
SELECT 'VIEW', table_name FROM information_schema.views WHERE table_schema = #{schema}
UNION ALL
SELECT ROUTINE_TYPE, ROUTINE_NAME FROM information_schema.routines WHERE ROUTINE_SCHEMA = #{schema}
UNION ALL
SELECT 'TRIGGER', trigger_name FROM information_schema.triggers WHERE trigger_schema = #{schema}
UNION ALL
SELECT 'EVENT', event_name FROM information_schema.events WHERE event_schema = #{schema}
